        selectedNode={connectorNode}
        selectedEdge={null}
        onUpdateNode={noop}
        onUpdateEdge={noop}
        onDeleteNode={noop}
        onDeleteEdge={noop}
        onClose={noop}
        isCampusActive={false}
        connectorCandidates={{
          above: [
            {
              nodeId: 'ramp-f3',
